// 读取规则文档内容并解析排版规则
var ruleDoc = null;
try {
    // 尝试获取已打开的规则.docx 文档
    var docs = Application.Documents;
    for (var i = 1; i <= docs.Count; i++) {
        if (docs.Item(i).Name === "规则.docx") {
            ruleDoc = docs.Item(i);
            break;
        }
    }
} catch (e) {
    return { error: "无法找到规则文档", details: e.message };
}

if (!ruleDoc) {
    return { error: "未找到规则.docx 文档" };
}

// 读取规则文档的所有段落
var rulesContent = "";
var paras = ruleDoc.Paragraphs;
for (var i = 1; i <= paras.Count; i++) {
    rulesContent += paras.Item(i).Range.Text + "\n";
}

return { 
    success: true, 
    content: rulesContent.substring(0, 2000), // 返回前 2000 字符用于分析
    totalLength: rulesContent.length
};
